qry:select.qry:xquery:
for $r in table('select PER02_PERSONAL_EMP.OI_PERSONAL_EMP IDD , E_NUMERO_LEGAJO, D_APE_Y_NOM from PER02_PERSONAL_EMP, org03_empresas , PER01_PERSONAL, liq19_liquidacion , liq07_personal where liq07_personal.oi_personal_emp = per02_personal_emp.oi_personal_emp AND
PER02_PERSONAL_EMP.OI_PERSONAL = PER01_PERSONAL.OI_PERSONAL and liq19_liquidacion.oi_empresa = org03_empresas.oi_empresa AND liq19_liquidacion.OI_LIQUIDACION = {#SOURCE:helper-mess/@liq} and PER02_PERSONAL_EMP.OI_PERSONAL_EMP not in (select liq25_personal_liq.oi_personal_emp from liq25_personal_liq where liq25_personal_liq.oi_liquidacion = {%= #SOURCE:helper-mess/@liq %}) AND {%? (string(#SOURCE:helper-mess/rows/row/@oi_personal_emp)!='') {% PER02_PERSONAL_EMP.OI_PERSONAL_EMP not in ({%=string(#SOURCE:helper-mess/rows/row/@oi_personal_emp) %}) %} {% 1 = 1 %} %}
AND PER02_PERSONAL_EMP.oi_empresa = org03_empresas.oi_empresa ')/ROWS/ROW
